import React, { useState } from 'react';
import { hot } from 'react-hot-loader/root';
import { ThemeProvider } from '@material-ui/core/styles';
import {
  Box,
  Button,
  CssBaseline,
  Typography,
} from '@material-ui/core';
import useMediaQuery from '@material-ui/core/useMediaQuery';
import theme from './theme';
import { ResearchPage } from './ResearchPage';
import { PublicationsPage } from './PublicationsPage';

const cv = '/pdf/CV_HyunsungCho.pdf';

const App = () => {
  const [currentTab, setCurrentTab] = useState('research');
  const isSmall = useMediaQuery('(max-width:600px)');
  const isMedium = useMediaQuery('(max-width:960px)');

  let size = 'large';
  if (isSmall) {
    size = 'small';
  } else if (isMedium) {
    size = 'medium';
  }

  const headerFontSize = isSmall ? 22 : 28;
  const subheaderFontSize = isSmall ? 14 : 20;
  const dividerFontSize = isSmall ? 12 : 18;

  const renderTabButton = (label, value) => (
    <Button
      onClick={() => setCurrentTab(value)}
      color="primary"
      style={{
        textTransform: 'none',
        fontFamily: 'Helvetica, Arial, sans-serif',
        fontSize: subheaderFontSize,
        fontWeight: 200,
        padding: 0,
        minWidth: 'auto',
      }}
    >
      <span
        style={{
          textDecoration: currentTab === value ? 'underline' : 'none',
          textDecorationColor: theme.customColors.brand,
          color: theme.palette.text.primary,
        }}
      >
        {label}
      </span>
    </Button>
  );

  return (
    <ThemeProvider theme={theme}>
      <CssBaseline />
      <Box
        display="flex"
        flexDirection="column"
        minHeight="100vh"
        bgcolor={theme.palette.background.default}
      >
        <Box
          component="header"
          display="flex"
          flexDirection={isSmall ? 'column' : 'row'}
          justifyContent="space-between"
          alignItems={isSmall ? 'flex-start' : 'center'}
          px={isSmall ? 2 : 8}
          py={isSmall ? 3 : 6}
        >
          <Box
            display="flex"
            alignItems="center"
            flexDirection="row"
            mb={isSmall ? 2 : 0}
          >
            <Typography
              style={{
                fontSize: headerFontSize,
                fontWeight: 700,
                marginRight: 8,
                color: theme.customColors.heavy,
              }}
            >
              HYUNSUNG CHO
            </Typography>
            <Typography
              style={{
                fontSize: dividerFontSize,
                fontWeight: 200,
                color: theme.customColors.brand,
                marginRight: 8,
              }}
            >
              |
            </Typography>
            <Typography
              style={{
                fontSize: headerFontSize,
                fontWeight: 700,
                color: theme.customColors.heavy,
              }}
            >
              조현성
            </Typography>
          </Box>
          <Box display="flex" alignItems="center">
            {renderTabButton('Research', 'research')}
            <Typography
              style={{
                fontSize: dividerFontSize,
                fontWeight: 200,
                color: theme.customColors.brand,
                margin: '0 12px',
              }}
            >
              |
            </Typography>
            <Button
              component="a"
              href={cv}
              target="_blank"
              rel="noopener noreferrer"
              color="primary"
              style={{
                textTransform: 'none',
                fontFamily: 'Helvetica, Arial, sans-serif',
                fontSize: subheaderFontSize,
                fontWeight: 200,
                padding: 0,
                minWidth: 'auto',
                color: theme.palette.text.primary,
              }}
            >
              CV
            </Button>
          </Box>
        </Box>
        <Box flexGrow={1} display="flex">
          {currentTab === 'research' ? (
            <ResearchPage size={size} />
          ) : (
            <PublicationsPage size={size} />
          )}
        </Box>
      </Box>
    </ThemeProvider>
  );
};

export default hot(App);
