const isLatestNews = (dateStr) => {
  const months = [
    'Jan',
    'Feb',
    'Mar',
    'Apr',
    'May',
    'Jun',
    'Jul',
    'Aug',
    'Sep',
    'Oct',
    'Nov',
    'Dec',
  ];
  const today = new Date();
  const thisMonth = today.getMonth();
  const thisYear = today.getFullYear();
  const [newsMonth, newsYear] = dateStr.split(' ');

  if (Number.isNaN(Number(newsYear))) {
    return true;
  }

  if (thisYear - 1 > Number(newsYear)) {
    return false;
  }

  if (thisYear > Number(newsYear) && months.indexOf(newsMonth) < thisMonth) {
    return false;
  }

  return true;
};

